import torch.nn.functional as F


class NCETrainer:
    """
    Noise Contrastive Estimation for EBMs.
    Avoids MCMC: uses a known noise distribution q instead.
    """
    def __init__(self, energy_net: nn.Module, noise_ratio: int = 5):
        self.energy_net = energy_net
        self.k = noise_ratio              # number of noise samples per data sample
        self.log_Z = nn.Parameter(torch.zeros(1))   # learn log Z_theta

    def sample_noise(self, n: int, x_shape: tuple, device) -> torch.Tensor:
        """Noise distribution q: standard Gaussian (or uniform)."""
        return torch.randn(n, *x_shape, device=device)

    def loss(self, x_pos: torch.Tensor) -> torch.Tensor:
        """
        NCE loss: treat real vs noise as a binary classification problem.
        """
        B = x_pos.shape[0]
        x_neg = self.sample_noise(B * self.k, x_pos.shape[1:], x_pos.device)

        # unnormalised log p_theta(x) = -E_theta(x) + c, c = -log Z
        # log q(x) for Gaussian: -0.5 * ||x||^2 - const (const cancels in ratio)
        def log_model(x):
            return -self.energy_net(x) + self.log_Z

        def log_noise(x):
            return -0.5 * x.flatten(1).pow(2).sum(-1)   # Gaussian log-prob (unnorm)

        # h(x) = log p_model(x) - log [p_model(x) + k*q(x)]
        #       = log_model(x) - log(exp(log_model(x)) + k*exp(log_noise(x)))
        def binary_log_prob(x, is_real: bool):
            lm = log_model(x)
            ln = log_noise(x) + torch.log(torch.tensor(self.k, dtype=torch.float))
            # numerically stable: log sigmoid of (lm - ln)
            logit = lm - ln
            if is_real:
                return F.logsigmoid(logit)
            else:
                return F.logsigmoid(-logit)

        loss_pos = -binary_log_prob(x_pos, is_real=True).mean()
        loss_neg = -binary_log_prob(x_neg, is_real=False).mean()
        return loss_pos + loss_neg
